import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

export default function Login() {
  const { login } = useAuth();
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await login(form);
      toast.success('Welcome back!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center',
      background: 'var(--bg)', padding: 20
    }}>
      <div style={{ width: '100%', maxWidth: 420 }}>
        <div style={{ textAlign: 'center', marginBottom: 32 }}>
          <h1 style={{ fontSize: 36, color: 'var(--accent)', marginBottom: 8 }}>⚡ TeamTask</h1>
          <p style={{ color: 'var(--text2)' }}>Sign in to your workspace</p>
        </div>

        <div className="card">
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Email</label>
              <input type="email" placeholder="you@example.com" value={form.email}
                onChange={e => setForm({...form, email: e.target.value})} required />
            </div>
            <div className="form-group">
              <label>Password</label>
              <input type="password" placeholder="••••••••" value={form.password}
                onChange={e => setForm({...form, password: e.target.value})} required />
            </div>
            <button type="submit" className="btn btn-primary" style={{ width: '100%', justifyContent: 'center', marginTop: 8 }} disabled={loading}>
              {loading ? 'Signing in...' : '→ Sign In'}
            </button>
          </form>
          <p style={{ textAlign: 'center', marginTop: 20, fontSize: 14, color: 'var(--text2)' }}>
            No account? <Link to="/register">Register here</Link>
          </p>
        </div>

        <div style={{ marginTop: 20, padding: 16, background: 'rgba(108,99,255,0.1)', borderRadius: 8, border: '1px solid rgba(108,99,255,0.3)' }}>
          <p style={{ fontSize: 12, color: 'var(--text2)', marginBottom: 6 }}>💡 Demo Accounts:</p>
          <p style={{ fontSize: 12, color: 'var(--text3)' }}>Register with role=<strong style={{color:'var(--accent)'}}>admin</strong> to create projects & tasks</p>
          <p style={{ fontSize: 12, color: 'var(--text3)' }}>Register with role=<strong style={{color:'var(--info)'}}>member</strong> to view & submit tasks</p>
        </div>
      </div>
    </div>
  );
}
